# --- 📈 ANALİZ SEKEMESİ İÇİN GÜNCEL VERİ OKUMA BLOĞU ---with tabs[1]:     st.header("📈 Gelişmiş Performans Analizi")    try:        # Veriyi tazele        df_g = conn.read(worksheet="gorusmeler", ttl=0)                # Sütun isimlerini temizle (Başındaki sonundaki boşlukları atar)        df_g.columns = df_g.columns.str.strip()        if not df_g.empty:            st.subheader("👥 Personel Görüşme Dağılımı")                        # Sütun var mı kontrol et, yoksa hata verme, kullanıcıyı uyar            target_col = "Görüşmeyi Yapan"            if target_col in df_g.columns:                # Verideki boşlukları doldur                df_g[target_col] = df_g[target_col].replace('', 'Bilinmiyor').fillna('Bilinmiyor')                                perf_data = df_g[target_col].value_counts().reset_index()                perf_data.columns = ['Personel', 'Görüşme Sayısı']                                fig_p = px.bar(                    perf_data,                     x='Personel',                     y='Görüşme Sayısı',                     color='Personel',                    text_auto=True,                    title="Personel Performans Grafiği"                )                st.plotly_chart(fig_p, use_container_width=True)            else:                st.error(f"⚠️ HATA: Tablonuzda '{target_col}' başlıklı bir sütun bulunamadı. Lütfen Excel başlığını kontrol edin.")        else:            st.info("📊 Analiz yapılacak veri henüz sisteme girilmemiş.")    except Exception as e:        st.error(f"Sistemsel bir hata oluştu: {e}")